import { Ionicons } from '@expo/vector-icons';
import { LinearGradient } from 'expo-linear-gradient';
import * as Haptics from 'expo-haptics';
import { router, useLocalSearchParams } from 'expo-router';
import Colors from '@/constants/colors';
import { useApp } from '@/lib/AppContext';
import { PulsingDot } from '@/components/PulsingDot';
import type { ChatMessage } from '@/lib/types';
import VoiceModeOverlay from '@/components/VoiceModeOverlay';
import { enqueue } from '@/lib/offlineQueue';

const C = Colors.dark;

function getDateLabel(timestamp: number): string {
  const d = new Date(timestamp);
  const now = new Date();
  const today = new Date(now.getFullYear(), now.getMonth(), now.getDate());
  const msgDay = new Date(d.getFullYear(), d.getMonth(), d.getDate());
  const diff = today.getTime() - msgDay.getTime();
  const dayMs = 86400000;
  if (diff < dayMs && diff >= 0) return 'Today';
  if (diff < dayMs * 2 && diff >= dayMs) return 'Yesterday';
  return d.toLocaleDateString(undefined, { month: 'short', day: 'numeric' });
}

function isSameDay(a: number, b: number): boolean {
  const da = new Date(a);
  const db = new Date(b);
  return da.getFullYear() === db.getFullYear() && da.getMonth() === db.getMonth() && da.getDate() === db.getDate();
}

function DateSeparator({ label }: { label: string }) {
  return (
    <View style={styles.dateSeparator}>
      <View style={styles.dateLine} />
      <Text style={styles.dateLabel}>{label}</Text>
      <View style={styles.dateLine} />
    </View>
  );
}

function renderFormattedText(content: string, isUser: boolean): React.ReactNode[] {
  const parts: React.ReactNode[] = [];
  const codeBlockRegex = /```[\s\S]*?```/g;
  let lastIndex = 0;
  let match: RegExpExecArray | null;

  const textColor = isUser ? '#FFFFFF' : C.text;
  const codeInlineBg = isUser ? 'rgba(0,0,0,0.25)' : 'rgba(255,255,255,0.08)';

  const renderInlineText = (text: string, key: string): React.ReactNode[] => {
    const inlineNodes: React.ReactNode[] = [];
    // Inline patterns: bold, italic, inline code, markdown links, bare URLs
    const inlineRegex = /(`[^`]+`)|(\*\*(.+?)\*\*)|(\*(.+?)\*)|(\[([^\]]+)\]\(([^)]+)\))|(https?:\/\/[^\s)\]]+)/g;
    let inlineLastIndex = 0;
    let inlineMatch: RegExpExecArray | null;
    let inlineKey = 0;

    while ((inlineMatch = inlineRegex.exec(text)) !== null) {
      if (inlineMatch.index > inlineLastIndex) {
        inlineNodes.push(
          <Text key={`${key}-t${inlineKey++}`}>{text.slice(inlineLastIndex, inlineMatch.index)}</Text>
        );
      }
      if (inlineMatch[1]) {
        // Inline code `...`
        const codeText = inlineMatch[1].slice(1, -1);
        inlineNodes.push(
          <Text
            key={`${key}-ic${inlineKey++}`}
            style={{
              fontFamily: Platform.OS === 'ios' ? 'Menlo' : 'monospace',
              fontSize: 13,
              backgroundColor: codeInlineBg,
              paddingHorizontal: 4,
              borderRadius: 4,
              color: isUser ? '#FFD4C4' : C.coral,
            }}
          >{codeText}</Text>
        );
      } else if (inlineMatch[2]) {
        // Bold **...**
        inlineNodes.push(
          <Text key={`${key}-b${inlineKey++}`} style={{ fontFamily: 'Inter_700Bold' }}>{inlineMatch[3]}</Text>
        );
      } else if (inlineMatch[4]) {
        // Italic *...*
        inlineNodes.push(
          <Text key={`${key}-i${inlineKey++}`} style={{ fontStyle: 'italic' }}>{inlineMatch[5]}</Text>
        );
      } else if (inlineMatch[6]) {
        // Markdown link [text](url)
        const linkText = inlineMatch[7];
        const linkUrl = inlineMatch[8];
        inlineNodes.push(
          <Text
            key={`${key}-ml${inlineKey++}`}
            style={{ color: C.coral, textDecorationLine: 'underline' }}
            onPress={() => Linking.openURL(linkUrl)}
          >{linkText}</Text>
        );
      } else if (inlineMatch[9]) {
        // Bare URL
        const url = inlineMatch[9];
        inlineNodes.push(
          <Text
            key={`${key}-l${inlineKey++}`}
            style={{ color: C.coral, textDecorationLine: 'underline' }}
            onPress={() => Linking.openURL(url)}
          >{url}</Text>
        );
      }
      inlineLastIndex = inlineMatch.index + inlineMatch[0].length;
    }
    if (inlineLastIndex < text.length) {
      inlineNodes.push(<Text key={`${key}-tail`}>{text.slice(inlineLastIndex)}</Text>);
    }
    if (inlineNodes.length === 0) {
      inlineNodes.push(<Text key={`${key}-empty`}>{text}</Text>);
    }
    return inlineNodes;
  };

  const renderTextBlock = (text: string, key: string) => {
    // Split text into lines so we can handle headers and lists
    const lines = text.split('\n');
    const lineNodes: React.ReactNode[] = [];

    for (let i = 0; i < lines.length; i++) {
      const line = lines[i];
      const lineKey = `${key}-ln${i}`;

      // Header (# ## ### etc)
      const headerMatch = line.match(/^(#{1,4})\s+(.*)/);
      if (headerMatch && !isUser) {
        const level = headerMatch[1].length;
        const headerSizes = [20, 17, 15, 14];
        lineNodes.push(
          <Text
            key={lineKey}
            style={{
              fontFamily: 'Inter_700Bold',
              fontSize: headerSizes[level - 1] || 14,
              color: textColor,
              marginTop: i > 0 ? 10 : 2,
              marginBottom: 4,
            }}
          >
            {renderInlineText(headerMatch[2], lineKey)}
          </Text>
        );
        continue;
      }

      // Bullet list (- or * )
      const bulletMatch = line.match(/^(\s*)[-*]\s+(.*)/);
      if (bulletMatch) {
        const indent = Math.min(Math.floor((bulletMatch[1]?.length || 0) / 2), 3);
        lineNodes.push(
          <View key={lineKey} style={{ flexDirection: 'row', marginLeft: indent * 12, marginTop: 3, paddingRight: 8 }}>
            <Text style={{ color: isUser ? 'rgba(255,255,255,0.6)' : C.coral, fontSize: 14, marginRight: 6, lineHeight: 20 }}>•</Text>
            <Text style={[styles.bubbleText, isUser ? styles.bubbleTextUser : styles.bubbleTextAssistant, { flex: 1, marginBottom: 0 }]}>
              {renderInlineText(bulletMatch[2], lineKey)}
            </Text>
          </View>
        );
        continue;
      }

      // Numbered list (1. 2. etc)
      const numMatch = line.match(/^(\s*)(\d+)\.\s+(.*)/);
      if (numMatch) {
        const indent = Math.min(Math.floor((numMatch[1]?.length || 0) / 2), 3);
        lineNodes.push(
          <View key={lineKey} style={{ flexDirection: 'row', marginLeft: indent * 12, marginTop: 3, paddingRight: 8 }}>
            <Text style={{ color: isUser ? 'rgba(255,255,255,0.6)' : C.textSecondary, fontSize: 14, marginRight: 6, lineHeight: 20, minWidth: 18 }}>{numMatch[2]}.</Text>
            <Text style={[styles.bubbleText, isUser ? styles.bubbleTextUser : styles.bubbleTextAssistant, { flex: 1, marginBottom: 0 }]}>
              {renderInlineText(numMatch[3], lineKey)}
            </Text>
          </View>
        );
        continue;
      }

      // Empty line → small spacer
      if (line.trim() === '') {
        lineNodes.push(<View key={lineKey} style={{ height: 8 }} />);
        continue;
      }

      // Regular text line
      if (i > 0 && lines[i - 1].trim() !== '' && !headerMatch) {
        // Continuing paragraph — add inline with newline
        lineNodes.push(
          <Text
            key={lineKey}
            style={[styles.bubbleText, isUser ? styles.bubbleTextUser : styles.bubbleTextAssistant]}
          >
            {renderInlineText(line, lineKey)}
          </Text>
        );
      } else {
        lineNodes.push(
          <Text
            key={lineKey}
            style={[styles.bubbleText, isUser ? styles.bubbleTextUser : styles.bubbleTextAssistant]}
          >
            {renderInlineText(line, lineKey)}
          </Text>
        );
      }
    }

    return lineNodes;
  };

  while ((match = codeBlockRegex.exec(content)) !== null) {
    if (match.index > lastIndex) {
      const textBefore = content.slice(lastIndex, match.index);
      parts.push(...renderTextBlock(textBefore, `tb-${lastIndex}`));
    }
    // Extract language label
    const langMatch = match[0].match(/^```(\w+)/);
    const lang = langMatch ? langMatch[1] : 'code';
    const codeContent = match[0].replace(/^```\w*\n?/, '').replace(/\n?```$/, '');
    parts.push(
      <View
        key={`code-${match.index}`}
        style={{
          backgroundColor: isUser ? 'rgba(0,0,0,0.2)' : 'rgba(0,0,0,0.3)',
          padding: 10,
          borderRadius: 8,
          marginVertical: 4,
        }}
      >
        <Text style={{
          fontSize: 9,
          color: C.textTertiary,
          position: 'absolute',
          top: 4,
          right: 6,
          textTransform: 'uppercase',
          letterSpacing: 0.5,
        }}>{lang}</Text>
        <Text style={{
          fontFamily: Platform.OS === 'ios' ? 'Menlo' : 'monospace',
          fontSize: 12,
          color: isUser ? '#FFFFFF' : C.text,
          lineHeight: 18,
        }}>{codeContent}</Text>
      </View>
    );
    lastIndex = match.index + match[0].length;
  }

  if (lastIndex < content.length) {
    const remaining = content.slice(lastIndex);
    parts.push(...renderTextBlock(remaining, `tb-${lastIndex}`));
  }

  if (parts.length === 0) {
    parts.push(
      <Text
        key="full"
        style={[styles.bubbleText, isUser ? styles.bubbleTextUser : styles.bubbleTextAssistant]}
      >
        {content}
      </Text>
    );
  }

  return parts;
}

const MessageBubble = React.memo(function MessageBubble({
  message,
  showAvatar,
  tightTop,
  onLongPress,
  copiedId,
}: {
  message: ChatMessage;
  showAvatar: boolean;
  tightTop: boolean;
  onLongPress: (id: string) => void;
  copiedId: string | null;
}) {
  const isUser = message.role === 'user';

  return (
    <View style={tightTop ? { marginTop: -2 } : undefined}>
      <Pressable
        onLongPress={() => {
          Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Medium);
          onLongPress(message.id);
        }}
        delayLongPress={400}
        style={({ pressed }) => [pressed && { opacity: 0.85 }]}
      >
        <View
          style={[
            styles.bubbleWrap,
            isUser ? styles.bubbleWrapUser : styles.bubbleWrapAssistant,
          ]}
        >
          {!isUser && showAvatar && (
            <LinearGradient
              colors={C.gradient.lobster}
              style={styles.assistantAvatar}
            >
              <Ionicons name="sparkles" size={12} color="#fff" />
            </LinearGradient>
          )}
          {!isUser && !showAvatar && <View style={{ width: 28 }} />}
          <View
            style={[
              styles.bubble,
              isUser ? styles.bubbleUser : styles.bubbleAssistant,
            ]}
          >
            {renderFormattedText(message.content, isUser)}
            <View style={styles.bubbleFooter}>
              <Text
                style={[
                  styles.bubbleTime,
                  isUser ? styles.bubbleTimeUser : styles.bubbleTimeAssistant,
                ]}
              >
                {new Date(message.timestamp).toLocaleTimeString(undefined, {
                  hour: '2-digit',
                  minute: '2-digit',
                })}
              </Text>
              {isUser && message.status === 'sent' && (
                <Ionicons name="checkmark-done" size={14} color="rgba(255,255,255,0.5)" style={{ marginLeft: 4 }} />
              )}
              {isUser && message.status === 'sending' && (
                <Ionicons name="checkmark" size={14} color="rgba(255,255,255,0.35)" style={{ marginLeft: 4 }} />
              )}
            </View>
          </View>
        </View>
      </Pressable>
      {copiedId === message.id && (
        <View style={[styles.copiedBadge, isUser ? { alignSelf: 'flex-end' } : { alignSelf: 'flex-start', marginLeft: 36 }]}>
          <Ionicons name="checkmark-circle" size={12} color={C.success} />
          <Text style={styles.copiedText}>Copied!</Text>
        </View>
      )}
    </View>
  );
}, (prevProps, nextProps) => {
  return (
    prevProps.message.id === nextProps.message.id &&
    prevProps.message.content === nextProps.message.content &&
    prevProps.message.status === nextProps.message.status &&
    prevProps.showAvatar === nextProps.showAvatar &&
    prevProps.tightTop === nextProps.tightTop &&
    prevProps.copiedId === nextProps.copiedId &&
    prevProps.onLongPress === nextProps.onLongPress
  );
});

function TypingIndicator() {
  const dot1 = useRef(new Animated.Value(0.3)).current;
  const dot2 = useRef(new Animated.Value(0.3)).current;
  const dot3 = useRef(new Animated.Value(0.3)).current;

  useEffect(() => {
    const animate = (dot: Animated.Value, delay: number) =>
      Animated.loop(
        Animated.sequence([
          Animated.delay(delay),
          Animated.timing(dot, { toValue: 1, duration: 400, useNativeDriver: Platform.OS !== 'web' }),
          Animated.timing(dot, { toValue: 0.3, duration: 400, useNativeDriver: Platform.OS !== 'web' }),
        ]),
      );
    const a1 = animate(dot1, 0);
    const a2 = animate(dot2, 200);
    const a3 = animate(dot3, 400);
    a1.start(); a2.start(); a3.start();
    return () => { a1.stop(); a2.stop(); a3.stop(); };
  }, [dot1, dot2, dot3]);

  return (
    <View style={[styles.bubbleWrap, styles.bubbleWrapAssistant]}>
      <LinearGradient colors={C.gradient.lobster} style={styles.assistantAvatar}>
        <Ionicons name="sparkles" size={12} color="#fff" />
      </LinearGradient>
      <View style={[styles.bubble, styles.bubbleAssistant, styles.typingBubble]}>
        <View style={styles.typingDots}>
          {[dot1, dot2, dot3].map((dot, i) => (
            <Animated.View
              key={i}
              style={[styles.typingDot, { opacity: dot }]}
            />
          ))}
        </View>
      </View>
    </View>
  );
}

function SuggestionChip({ text, onPress }: { text: string; onPress: () => void }) {
  return (
    <Pressable
      style={({ pressed }) => [styles.suggestionChip, pressed && { opacity: 0.7 }]}
      onPress={onPress}
