import React, { useState, useCallback, useEffect, useRef, useMemo } from 'react';
import {
  StyleSheet,
  View,
  ScrollView,
  Pressable,
  Platform,
  RefreshControl,
  Animated,
  Switch,
  ActivityIndicator,
  PanResponder,
  Text,
  type GestureResponderEvent,
  type PanResponderGestureState,
} from 'react-native';
import { useSafeAreaInsets } from 'react-native-safe-area-context';
import { Ionicons } from '@expo/vector-icons';
import { LinearGradient } from 'expo-linear-gradient';
import * as Haptics from 'expo-haptics';
import Colors from '@/constants/colors';
import { useApp } from '@/lib/AppContext';
import { getGateway } from '@/lib/gateway';
import { PulsingDot } from '@/components/PulsingDot';
import { GlassCard } from '@/components/GlassCard';
import { Typography } from '@/components/Typography';
import * as LocalAuthentication from 'expo-local-authentication';

const C = Colors.dark;

interface Automation {
  id: string;
  name: string;
  schedule: string;
  enabled: boolean;
  status: 'running' | 'paused' | 'error' | 'idle';
  lastRun?: number;
  lastOutput?: string;
  type: 'heartbeat' | 'cron';
}

interface PendingApproval {
  id: string;
  action: string;
  description: string;
  riskTier: 'P1' | 'P2' | 'P3';
  expiresAt: number;
  source?: string;
}

interface CronOutput {
  id: string;
  automationName: string;
  timestamp: number;
  success: boolean;
  output: string;
  duration?: number;
}

interface ToastState {
  visible: boolean;
  message: string;
  type: 'success' | 'error';
}

const RISK_TIER_CONFIG: Record<string, { color: string; label: string; glowColor: string }> = {
  P1: { color: C.error, label: 'CRITICAL', glowColor: C.error + '40' },
  P2: { color: C.amber, label: 'REVIEW', glowColor: C.amber + '30' },
  P3: { color: C.textSecondary, label: 'LOW', glowColor: C.textSecondary + '15' },
};



function formatTimeAgo(ts: number) {
  const diff = Date.now() - ts;
  const mins = Math.floor(diff / 60000);
  if (mins < 1) return 'Just now';
  if (mins < 60) return `${mins}m ago`;
  const hrs = Math.floor(mins / 60);
  if (hrs < 24) return `${hrs}h ago`;
  return `${Math.floor(hrs / 24)}d ago`;
}

function formatCountdown(expiresAt: number) {
  const diff = expiresAt - Date.now();
  if (diff <= 0) return 'Expired';
  const mins = Math.floor(diff / 60000);
  const secs = Math.floor((diff % 60000) / 1000);
  if (mins > 0) return `${mins}m ${secs} s`;
  return `${secs} s`;
}

function formatUptime(ms: number) {
  const hrs = Math.floor(ms / 3600000);
  const mins = Math.floor((ms % 3600000) / 60000);
  if (hrs > 0) return `${hrs}h ${mins} m`;
  return `${mins} m`;
}

