import WebSocket from 'ws';

export interface GatewayConfig {
    url: string;
    token: string;
}

export interface AuditEntry {
    timestamp: number;
    deviceId: string;
    action: string;
    result: 'success' | 'error';
    details?: string;
}

export interface PendingRPC {
    resolve: (v: any) => void;
    reject: (e: any) => void;
    timer: ReturnType<typeof setTimeout>;
}

export type GatewayStatus = 'disconnected' | 'connecting' | 'authenticating' | 'connected' | 'error';

export const state = {
    gatewayConfig: null as GatewayConfig | null,
    gatewayWs: null as WebSocket | null,
    gatewayStatus: 'disconnected' as GatewayStatus,
    gatewayInfo: {} as any,

    reconnectTimer: null as ReturnType<typeof setTimeout> | null,
    reconnectAttempts: 0,
    maxReconnectAttempts: 10,
    pingInterval: null as ReturnType<typeof setInterval> | null,

    pendingRPCs: new Map<string, PendingRPC>(),
    auditLog: [] as AuditEntry[],
    mobileClients: new Set<WebSocket>(),
    streamBuffers: new Map<string, string>(),
    authorizedDevices: new Map<string, { pairingCode: string; authorizedAt: number }>(),

    // Push notification token storage: deviceId -> { token, platform, lastSeen }
    pushTokens: new Map<string, { expoPushToken: string; platform: string; lastSeen: number }>(),

    // Track which deviceIds have active WS connections
    activeDeviceConnections: new Map<WebSocket, string>(),
};

const MAX_AUDIT_ENTRIES = 1000;

export function addAudit(deviceId: string, action: string, result: 'success' | 'error', details?: string) {
    state.auditLog.push({ timestamp: Date.now(), deviceId, action, result, details });
    if (state.auditLog.length > MAX_AUDIT_ENTRIES) {
        state.auditLog.splice(0, state.auditLog.length - MAX_AUDIT_ENTRIES);
    }
}

export function hasActiveMobileClients(): boolean {
    for (const client of state.mobileClients) {
        if (client.readyState === WebSocket.OPEN) return true;
    }
    return false;
}

export function broadcastToMobile(msg: any) {
    const data = JSON.stringify(msg);
    for (const client of state.mobileClients) {
        if (client.readyState === WebSocket.OPEN) {
            client.send(data);
        }
    }
}

export function sendToGateway(msg: any) {
    if (state.gatewayWs && state.gatewayWs.readyState === WebSocket.OPEN) {
        state.gatewayWs.send(JSON.stringify(msg));
    }
}

components/VoiceModeOverlay.tsx.content:
import React, { useState, useEffect, useCallback } from 'react';
import {
    StyleSheet,
    View,
    Text,
    Pressable,
    Modal,
    ActivityIndicator,
} from 'react-native';
import Animated, {
    useSharedValue,
    useAnimatedStyle,
    withRepeat,
    withTiming,
    withSequence,
    Easing,
    cancelAnimation,
    runOnJS
} from 'react-native-reanimated';
import { Ionicons } from '@expo/vector-icons';
import { BlurView } from 'expo-blur';
import * as Haptics from 'expo-haptics';
import Colors from '@/constants/colors';
import { useApp } from '@/lib/AppContext';
import {
    startRecording,
    stopRecording,
    speakText,
    stopSpeaking,
    requestAudioPermission,
} from '@/lib/voice';

const C = Colors.dark;

type VoiceState = 'idle' | 'listening' | 'processing' | 'speaking' | 'error';

interface VoiceModeOverlayProps {
    visible: boolean;
    onClose: () => void;
    onSend: (text: string) => Promise<string | void>;
}

function WaveformBar({ delay, color }: { delay: number; color: string }) {
    const scaleY = useSharedValue(0.3);

    useEffect(() => {
        const timeout = setTimeout(() => {
            scaleY.value = withRepeat(
                withSequence(
                    withTiming(1, { duration: 300 + Math.random() * 200, easing: Easing.inOut(Easing.ease) }),
                    withTiming(0.3, { duration: 300 + Math.random() * 200, easing: Easing.inOut(Easing.ease) })
                ),
                -1,
                true
            );
        }, delay);
        return () => {
            clearTimeout(timeout);
            cancelAnimation(scaleY);
        };
    }, [scaleY, delay]);

    const style = useAnimatedStyle(() => ({
        transform: [{ scaleY: scaleY.value }],
    }));

    return (
        <Animated.View
            style={[
                styles.waveBar,
                { backgroundColor: color },
                style,
            ]}
        />
    );
}

function PulseRing({ active, color }: { active: boolean; color: string }) {
    const scale = useSharedValue(1);
    const opacity = useSharedValue(0.3);

    useEffect(() => {
        if (!active) {
            cancelAnimation(scale);
            cancelAnimation(opacity);
            scale.value = 1;
            opacity.value = 0;
            return;
        }

        scale.value = 1;
        opacity.value = 0.3;

        scale.value = withRepeat(
            withTiming(2.2, { duration: 1200, easing: Easing.out(Easing.ease) }),
            -1,
            false
        );
        opacity.value = withRepeat(
            withTiming(0, { duration: 1200, easing: Easing.out(Easing.ease) }),
            -1,
            false
        );

        return () => {
            cancelAnimation(scale);
            cancelAnimation(opacity);
        };
    }, [active, scale, opacity]);

    const style = useAnimatedStyle(() => ({
        transform: [{ scale: scale.value }],
        opacity: opacity.value,
    }));

    if (!active) return null;

    return (
        <Animated.View
            style={[
                styles.pulseRing,
                { borderColor: color },
                style,
            ]}
        />
    );
}

export default function VoiceModeOverlay({ visible, onClose, onSend }: VoiceModeOverlayProps) {
    const [state, setState] = useState<VoiceState>('idle');
    const [transcribedText, setTranscribedText] = useState('');
    const [responseText, setResponseText] = useState('');
    const [errorMsg, setErrorMsg] = useState('');
    const fadeAnim = useSharedValue(0);

    useEffect(() => {
        if (visible) {
            fadeAnim.value = 0;
            fadeAnim.value = withTiming(1, {
                duration: 300,
                easing: Easing.out(Easing.ease),
            });
            setState('idle');
            setTranscribedText('');
            setResponseText('');
            setErrorMsg('');
        }
    }, [visible, fadeAnim]);

    const { gateway, gatewayStatus } = useApp();

    const handleStartListening = useCallback(async () => {
        Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Medium);

        const hasPermission = await requestAudioPermission();
        if (!hasPermission) {
            setErrorMsg('Microphone permission is required');
            setState('error');
            return;
        }

        const started = await startRecording({
            onChunk: (base64) => {
                if (gatewayStatus === 'connected') {
                    // Send chunks immediately as they are recorded
                    gateway.streamAudioChunk(base64, 'agent:main:main').catch(() => { });
                }
            }
        });

        if (started) {
            setState('listening');
            setTranscribedText('');
            setResponseText('');
        } else {
            setErrorMsg('Failed to start recording');
            setState('error');
        }
    }, [gateway, gatewayStatus]);

    const handleStopListening = useCallback(async () => {
        Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Light);
        setState('processing');

        const result = await stopRecording();
        if (!result.uri && !result.base64) {
            setErrorMsg('No audio recorded');
            setState('error');
            return;
        }

        // Send end signal to gateway so it knows the audio file stream is finished
        if (gatewayStatus === 'connected') {
            gateway.endAudioStream('agent:main:main').catch(() => { });
        }

        // If the recording is too short, show an error
        if (result.durationMs < 500) {
            setErrorMsg('Recording too short — hold the button longer');
            setState('error');
            return;
        }

        // For now, we send a placeholder message indicating voice input
        // In production, the gateway transcribes the audio via its STT service
        const voiceIndicator = '🎤 [Voice message]';
        setTranscribedText(voiceIndicator);

        try {
            const response = await onSend(voiceIndicator);
            if (response) {
                setResponseText(response);
                setState('speaking');
                speakText(response, {
                    onDone: () => setState('idle'),
                });
            } else {
                setState('idle');
            }
        } catch {
            setErrorMsg('Failed to get response');
            setState('error');
        }
    }, [gateway, gatewayStatus, onSend]);

    const handleClose = useCallback(() => {
        stopSpeaking();
        if (state === 'listening') {
            stopRecording();
        }
        fadeAnim.value = withTiming(0, {
            duration: 200,
            easing: Easing.out(Easing.ease),
        }, (finished) => {
            if (finished) {
                runOnJS(onClose)();
            }
        });
    }, [fadeAnim, onClose, state]);

    const handleStopSpeaking = useCallback(() => {
        stopSpeaking();
        setState('idle');
    }, []);

    if (!visible) return null;

    const stateColor =
        state === 'listening' ? C.error :
            state === 'processing' ? C.amber :
                state === 'speaking' ? C.accent :
                    state === 'error' ? C.error :
                        C.textSecondary;

    const stateLabel =
        state === 'idle' ? 'Tap to speak' :
            state === 'listening' ? 'Listening...' :
                state === 'processing' ? 'Processing...' :
                    state === 'speaking' ? 'Speaking...' :
                        'Error';

    return (
        <Modal
            visible={visible}
            transparent
            animationType="none"
            onRequestClose={handleClose}
            statusBarTranslucent
        >
            <Animated.View style={[styles.overlay, { opacity: fadeAnim }]}>
                <BlurView intensity={40} tint="dark" style={styles.blurFill}>
                    {/* Close button */}
                    <Pressable style={styles.closeBtn} onPress={handleClose}>
                        <Ionicons name="close" size={24} color={C.textSecondary} />
                    </Pressable>

                    {/* Main content */}
                    <View style={styles.content}>
                        {/* Waveform visualization */}
                        {state === 'listening' && (
                            <View style={styles.waveformContainer}>
                                {Array.from({ length: 12 }).map((_, i) => (
                                    <WaveformBar key={i} delay={i * 50} color={stateColor} />
                                ))}
                            </View>
                        )}

                        {state === 'processing' && (
                            <ActivityIndicator size="large" color={C.amber} style={{ marginBottom: 24 }} />
                        )}

                        {state === 'speaking' && (
                            <View style={styles.waveformContainer}>
                                {Array.from({ length: 12 }).map((_, i) => (
                                    <WaveformBar key={i} delay={i * 80} color={C.accent} />
                                ))}
                            </View>
                        )}

                        {/* Pulse ring around mic button */}
                        <View style={styles.micBtnContainer}>
                            <PulseRing active={state === 'listening'} color={stateColor} />
                            <Pressable
                                style={[
                                    styles.micBtn,
                                    { borderColor: stateColor + '40' },
                                    state === 'listening' && { backgroundColor: stateColor + '20' },
                                ]}
                                onPress={() => {
                                    if (state === 'idle' || state === 'error') {
                                        handleStartListening();
                                    } else if (state === 'listening') {
                                        handleStopListening();
                                    } else if (state === 'speaking') {
                                        handleStopSpeaking();
                                    }
                                }}
                            >
                                <Ionicons
                                    name={
                                        state === 'listening' ? 'stop' :
                                            state === 'speaking' ? 'volume-mute' :
                                                'mic'
                                    }
                                    size={36}
                                    color={stateColor}
                                />
                            </Pressable>
                        </View>

                        {/* State label */}
                        <Text style={[styles.stateLabel, { color: stateColor }]}>
                            {stateLabel}
                        </Text>

                        {/* Transcribed text */}
                        {transcribedText ? (
                            <View style={styles.transcriptBox}>
                                <Text style={styles.transcriptLabel}>You said:</Text>
                                <Text style={styles.transcriptText}>{transcribedText}</Text>
                            </View>
                        ) : null}

                        {/* Response text */}
                        {responseText ? (
                            <View style={styles.responseBox}>
                                <Text style={styles.responseLabel}>Agent:</Text>
                                <Text style={styles.responseText} numberOfLines={6}>
                                    {responseText}
                                </Text>
                            </View>
                        ) : null}

                        {/* Error */}
                        {state === 'error' && (
                            <View style={styles.errorBox}>
                                <Ionicons name="alert-circle" size={16} color={C.error} />
                                <Text style={styles.errorText}>{errorMsg}</Text>
                            </View>
                        )}
                    </View>

                    {/* Bottom hint */}
                    <Text style={styles.hint}>
                        {state === 'listening'
                            ? 'Tap the mic to stop recording'
                            : state === 'speaking'
                                ? 'Tap the mic to stop speaking'
                                : 'Tap the mic to start a voice command'}
                    </Text>
                </BlurView>
            </Animated.View>
        </Modal>
    );
}

const styles = StyleSheet.create({
    overlay: {
        flex: 1,
    },
    blurFill: {
        flex: 1,
        justifyContent: 'center',
        alignItems: 'center',
        paddingHorizontal: 32,
    },
    closeBtn: {
        position: 'absolute',
        top: 60,
        right: 20,
        width: 40,
        height: 40,
        borderRadius: 20,
        backgroundColor: C.surface + '80',
        justifyContent: 'center',
        alignItems: 'center',
        zIndex: 10,
    },
    content: {
        alignItems: 'center',
        gap: 20,
        width: '100%',
    },
    waveformContainer: {
        flexDirection: 'row',
        alignItems: 'center',
        justifyContent: 'center',
        gap: 4,
        height: 50,
        marginBottom: 8,
    },
    waveBar: {
        width: 4,
        height: 40,
        borderRadius: 2,
    },
    micBtnContainer: {
        width: 100,
        height: 100,
        justifyContent: 'center',
        alignItems: 'center',
    },
    pulseRing: {
        position: 'absolute',
        width: 100,
        height: 100,
        borderRadius: 50,
        borderWidth: 2,
    },
    micBtn: {
        width: 80,
        height: 80,
        borderRadius: 40,
        backgroundColor: C.surface,
        justifyContent: 'center',
        alignItems: 'center',
